# Define a function
def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

# Calculate fibonacci
for i in range(10):
    print(f"fib({i}) = {fibonacci(i)}")

// Advanced FrontEnd API example
// Creating cells programmatically

const createMathCells = () => {
  const operations = [
    { expr: "2 + 2", desc: "Addition" },
    { expr: "10 * 5", desc: "Multiplication" },
    { expr: "100 / 4", desc: "Division" }
  ];

  operations.forEach(op => {
    const code = `// ${op.desc}\nconsole.log('${op.expr} =', ${op.expr});`;
    FrontEnd.CreateCell('code', code);
  });

  FrontEnd.ShowMessage(`Created ${operations.length} cells`, 'info');
};

